  { name: 'Cá rô phi', scientificName: 'Oreochromis niloticus' },
  { name: 'Heo rừng', scientificName: 'Sus scrofa' },
  { name: 'Gà rừng', scientificName: 'Gallus gallus' },
  { name: 'Trăn đất', scientificName: 'Python molurus bivittatus' },
  { name: 'Rắn hổ mang', scientificName: 'Naja naja' },
  { name: 'Hươu sao', scientificName: 'Cervus nippon' },
  { name: 'Nai', scientificName: 'Rusa unicolor' },
  { name: 'Nhập thủ công', scientificName: '' }, 
];

export default speciesOptions;
